patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 58137cd6f543..935ac13a14d1 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -16064,7 +16064,8 @@ void BoUpSLP::computeMinimumValueSizes() {
                     // considered.
                     if (TE->getOpcode() == Instruction::ICmp)
                       return true;
-                    return DL->getTypeSizeInBits(U->getType()) > UserTESz;
+                    if (!U->getType()->isSized()) return true; // Allow unsized types to proceed
+return DL->getTypeSizeInBits(U->getType()) > UserTESz;
                   }));
         })) {
       ToDemote.push_back(E.Idx);

